import{_ as e,o as i,c as t,Q as n}from"./chunks/framework.7ed72bc6.js";const f=JSON.parse('{"title":"Lightning 2.x April Release","description":"The April 2023 Lightning release brings exciting updates; Vite replaces rollup, Vitest introduced for unit testing, fixes for word wrapping and device pixel ratio. The SDK fixes a router backtrack issue. The CLI has several improvements and now comes with CORS support.","frontmatter":{"layout":"blog","title":"Lightning 2.x April Release","description":"The April 2023 Lightning release brings exciting updates; Vite replaces rollup, Vitest introduced for unit testing, fixes for word wrapping and device pixel ratio. The SDK fixes a router backtrack issue. The CLI has several improvements and now comes with CORS support.","date":"2023-4-28"},"headers":[],"relativePath":"blogs/releaseApril2023.md","filePath":"blogs/releaseApril2023.md"}'),a={name:"blogs/releaseApril2023.md"},o=n('<p>The new April release of Lightning is here, and it&#39;s packed with exciting updates and improvements that will make your development experience even smoother. Let&#39;s take a look at the changes:</p><h1 id="lightning-core" tabindex="-1">Lightning Core <a class="header-anchor" href="#lightning-core" aria-label="Permalink to &quot;Lightning Core&quot;">​</a></h1><p>First up, Lightning Core has been updated to version 2.10.0. One of the biggest changes is the integration of Vite to replace the rollup bundler. Additionally, Vitest has been integrated for unit testing.</p><p>Some other notable improvements in Lightning Core include the implementation of word wrapping support on zero-width breaking spaces, added support for device pixel ratio with the option devicePixelRatio, and fixes for text rendering at high precision levels causing incorrect word wrapping.</p><p>There are also some Typescript specific changes: the <code>getByRef()</code> error when using generic type param as Ref value, is fixed. And in this version of Lightning Core, default loose type configs are implemented for Typescript.</p><h1 id="lightning-sdk" tabindex="-1">Lightning SDK <a class="header-anchor" href="#lightning-sdk" aria-label="Permalink to &quot;Lightning SDK&quot;">​</a></h1><p>Next, the Lightning SDK has been updated to version 5.3.2, with a focus on fixing issues and improving overall stability. One of the most significant fixes is for the router backtrack issue, where the application was not behaving properly in case of deeplinks.</p><h1 id="lightning-cli" tabindex="-1">Lightning CLI <a class="header-anchor" href="#lightning-cli" aria-label="Permalink to &quot;Lightning CLI&quot;">​</a></h1><p>Finally, the Lightning CLI has been updated to version 2.11.0, with some useful new features and bug fixes.</p><p>We have removed the license texts from the fixtures used to create new Apps. So new apps created with the CLI don&#39;t come with unnecessary licenses anymore.</p><p>There&#39;s also a fix for a build issue related to the rollup path when using NPX, solving issues for the Metrological CLI. Plus, support for CORS has been added in <code>lng serve</code> via a new environment variable (<code>LNG_SERVE_CORS</code>).</p><h1 id="happy-coding" tabindex="-1">Happy coding <a class="header-anchor" href="#happy-coding" aria-label="Permalink to &quot;Happy coding&quot;">​</a></h1><p>That&#39;s all for the April `23 release. Go ahead and update your projects to take advantage of these new improvements and fixes. And Happy coding!</p>',13),r=[o];function s(p,l,h,d,c,g){return i(),t("div",null,r)}const m=e(a,[["render",s]]);export{f as __pageData,m as default};
